mapper.select:
SELECT t.id, t.name, t.color, t.status, t.created_at, t.updated_at, COUNT(ct.course_id) AS course_count FROM tag t LEFT JOIN course_tag ct ON t.id = ct.tag_id WHERE t.deleted_at IS NULL
AND t.name LIKE CONCAT('%', #{keyword}, '%')
AND t.status = #{status}
GROUP BY t.id, t.name, t.color, t.status, t.created_at, t.updated_at ORDER BY
course_count ${sortOrder}, t.name ASC t.created_at ${sortOrder} t.name ${sortOrder} t.updated_at ${sortOrder}
